#![allow(unused_imports)]
use std::mem;
use std::io;
use std::string;
use std::cmp::*;
use std::collections::*;

fn load() -> Vec<i64> {
    let mut line = String::new();
    io::stdin().read_line(&mut line).expect("Failed to read line");
    let vec: Vec<&str> = line.split(" ").collect();
    let mut data : Vec<i64> = Vec::new();
    for i in vec {
        let el : i64 = i.trim().parse().unwrap();
        data.push(el);
    }
    data
}
fn maxv(v : &Vec<i64>) -> i64{
    let mut s=v[0];
    for i in v {s=max(s,*i);}
    return s;
}
fn minv(v : &Vec<i64>) -> i64{
    let mut s=v[0];
    for i in v {s=min(s,*i);}
    return s;
}

fn main() {
    let a = load();
    let n=a[0];
    let k=a[1];
    let t=240-k;
    let mut sum = 0;
    let mut last = 0;
    for i in 1..n+1 {
        sum+=i*5;
        if sum > t {break;}
        last = i;
    }
    println!("{}", last);
}
